export async function seedCertificationQuestions(): Promise<{ inserted: number; skipped: number }> {
  const allQuestions = [
    ...BLS_QUESTIONS,
    ...ACLS_QUESTIONS,
    ...PALS_QUESTIONS,
    ...RESUSCITATION_CORE_QUESTIONS,
  ];

  let inserted = 0;
  let skipped = 0;

  for (const q of allQuestions) {
    try {
      const stemHash = Buffer.from(q.stem).toString("base64").substring(0, 40);
      const existing = await pool.query(
        `SELECT id FROM exam_questions WHERE stem_hash = $1 LIMIT 1`,
        [stemHash]
      );

      if (existing.rows.length > 0) {
        skipped++;
        continue;
      }

      await pool.query(
        `INSERT INTO exam_questions (
          id, tier, exam, question_type, status, stem, options, correct_answer,
          rationale, difficulty, tags, body_system, topic, stem_hash,
          career_type, region_scope, created_at, updated_at
        ) VALUES (
          gen_random_uuid(), $1, $2, $3, 'published', $4, $5, $6,
          $7, $8, $9, $10, $11, $12,
          'nursing', 'BOTH', NOW(), NOW()
        )`,
        [
          "newgrad",
          q.certification,
          q.questionType,
          q.stem,
          JSON.stringify(q.options),
          JSON.stringify(q.correctAnswer),
          q.rationale,
          q.difficulty,
          q.tags,
          q.bodySystem,
          q.topic,
          stemHash,
        ]
      );
      inserted++;
    } catch (err: any) {
      console.error(`[CertSeed] Error inserting question: ${err.message}`);
      skipped++;
    }
  }

  console.log(`[CertSeed] Completed: ${inserted} inserted, ${skipped} skipped`);
  return { inserted, skipped };
}
